section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/slo-definition-template-per-service-class.json",
  "type": "object",
  "required": [
    "slo_name",
    "service_id",
    "service_class",
    "sli_query",
    "target",
    "window_days",
    "rationale",
    "owner"
  ],
  "properties": {
    "slo_name": {
      "type": "string",
      "description": "string"
    },
    "service_id": {
      "type": "string",
      "description": "string (matches catalog)"
    },
    "service_class": {
      "type": "string",
      "description": "enum (http_api | async_worker | batch | static_asset | scheduled_job)"
    },
    "sli_query": {
      "type": "string",
      "description": "string (PromQL recording-rule reference)"
    },
    "target": {
      "type": "object",
      "description": "object (good_ratio_min | latency_p99_max | etc.)"
    },
    "window_days": {
      "type": "integer",
      "description": "integer (1 | 7 | 28 | 90)"
    },
    "rationale": {
      "type": "string",
      "description": "string (\u2264300 chars)"
    },
    "owner": {
      "type": "string",
      "description": "string"
    }
  }
}
